import React, { useState, useEffect } from 'react';
import {
  getEventsByOrganiser, createEvent, updateEvent, deleteEvent,
  getAllLocations, getSlotsByEvent, createSlot, updateSlot, deleteSlot,
} from '../../api/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const EMPTY_FORM = {
  name: '', type: 'MOVIE', genres: [], languages: [], venues: [],
  duration: '', categoryName: '', status: 'ACTIVE',
};
const EMPTY_SLOT_ROW = { showDate: '', startTime: '', endTime: '' };

const TYPES         = ['MOVIE', 'CONCERT', 'EVENT'];
const ALL_GENRES    = ['Action','Drama','Comedy','Romance','Horror','Thriller','Pop','Rock','Classical','Festival','Sports','Cultural','Other'];
const ALL_LANGUAGES = ['English','Tamil','Hindi','Telugu','Malayalam','Kannada','French','Japanese'];
const TYPE_COLOR    = { MOVIE: 'var(--blue)', CONCERT: 'var(--gold)', EVENT: 'var(--green)' };

const parseList = (str) => (!str ? [] : str.split(',').map((s) => s.trim()).filter(Boolean));
const newRow    = ()    => ({ ...EMPTY_SLOT_ROW, _id: Date.now() + Math.random() });

// ── Tag picker ────────────────────────────────────────────────────────────────
const TagPicker = ({ options, selected, onChange, label }) => (
  <div className="form-group">
    <label className="form-label">
      {label}{' '}
      <span style={{ fontWeight: 400, color: 'var(--text-muted)', fontSize: '11px' }}>(select one or more)</span>
    </label>
    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '7px' }}>
      {options.map((opt) => {
        const active = selected.includes(opt);
        return (
          <button key={opt} type="button"
            onClick={() => onChange(active ? selected.filter((x) => x !== opt) : [...selected, opt])}
            style={{
              padding: '5px 13px', borderRadius: '20px', border: '1.5px solid',
              fontSize: '12px', fontWeight: 600, cursor: 'pointer',
              fontFamily: 'var(--font-body)', transition: 'all 0.15s',
              borderColor: active ? 'var(--accent)' : 'var(--border)',
              background:  active ? 'var(--accent-dim)' : 'var(--bg-secondary)',
              color:       active ? 'var(--accent)' : 'var(--text-secondary)',
            }}>
            {active && '✓ '}{opt}
          </button>
        );
      })}
    </div>
    {selected.length > 0 && (
      <div style={{ marginTop: '7px', fontSize: '12px', color: 'var(--text-muted)' }}>
        Selected: <span style={{ color: 'var(--accent)', fontWeight: 700 }}>{selected.join(', ')}</span>
      </div>
    )}
  </div>
);

// ── Venue picker ──────────────────────────────────────────────────────────────
const VenuePicker = ({ locations, selected, onChange }) => (
  <div className="form-group" style={{ gridColumn: '1/-1' }}>
    <label className="form-label">
      Venue / Address{' '}
      <span style={{ fontWeight: 400, color: 'var(--text-muted)', fontSize: '11px' }}>(select one or more)</span>
    </label>
    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '7px' }}>
      {locations.map((l) => {
        const val    = l.locName;
        const active = selected.includes(val);
        return (
          <button key={l.locationId} type="button"
            onClick={() => onChange(active ? selected.filter((x) => x !== val) : [...selected, val])}
            style={{
              padding: '6px 14px', borderRadius: '10px', border: '1.5px solid',
              fontSize: '12px', fontWeight: 600, cursor: 'pointer', textAlign: 'left',
              fontFamily: 'var(--font-body)', transition: 'all 0.15s',
              borderColor: active ? 'var(--accent)' : 'var(--border)',
              background:  active ? 'var(--accent-dim)' : 'var(--bg-secondary)',
              color:       active ? 'var(--accent)' : 'var(--text-secondary)',
            }}>
            {active && '✓ '}📍 {l.locName}{l.address ? ` — ${l.address}` : ''}
          </button>
        );
      })}
    </div>
    {selected.length > 0 && (
      <div style={{ marginTop: '7px', fontSize: '12px', color: 'var(--text-muted)' }}>
        Selected: <span style={{ color: 'var(--accent)', fontWeight: 700 }}>{selected.join(', ')}</span>
      </div>
    )}
  </div>
);

// ── Slot row builder ──────────────────────────────────────────────────────────
const SlotBuilder = ({ rows, onChange, onAdd, onRemove }) => (
  <div style={{ gridColumn: '1/-1' }}>
    {/* divider */}
    <div style={{ display: 'flex', alignItems: 'center', gap: '10px', margin: '4px 0 12px' }}>
      <div style={{ flex: 1, height: '1px', background: 'var(--border)' }} />
      <span style={{ fontSize: '11px', fontWeight: 700, color: 'var(--text-muted)', letterSpacing: '0.06em' }}>SHOW TIMINGS</span>
      <div style={{ flex: 1, height: '1px', background: 'var(--border)' }} />
    </div>

    {rows.length === 0 && (
      <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '10px', fontStyle: 'italic' }}>
        No show timings added — slots will not be created automatically.
      </div>
    )}

    {rows.map((row, i) => (
      <div key={row._id} style={{
        display: 'grid', gridTemplateColumns: '1fr 1fr 1fr auto',
        gap: '8px', alignItems: 'end', marginBottom: '8px',
        padding: '10px 12px', borderRadius: '10px',
        background: 'var(--bg-secondary)', border: '1px solid var(--border)',
      }}>
        <div className="form-group" style={{ margin: 0 }}>
          {i === 0 && <label className="form-label" style={{ fontSize: '11px' }}>Date *</label>}
          <input
            type="date" className="form-input"
            value={row.showDate}
            onChange={(e) => onChange(i, 'showDate', e.target.value)}
          />
        </div>
        <div className="form-group" style={{ margin: 0 }}>
          {i === 0 && <label className="form-label" style={{ fontSize: '11px' }}>Start *</label>}
          <input
            type="time" className="form-input"
            value={row.startTime}
            onChange={(e) => onChange(i, 'startTime', e.target.value)}
          />
        </div>
        <div className="form-group" style={{ margin: 0 }}>
          {i === 0 && <label className="form-label" style={{ fontSize: '11px' }}>End</label>}
          <input
            type="time" className="form-input"
            value={row.endTime}
            onChange={(e) => onChange(i, 'endTime', e.target.value)}
          />
        </div>
        <button
          type="button"
          onClick={() => onRemove(i)}
          style={{
            width: 32, height: 32, borderRadius: '8px', border: '1px solid var(--border)',
            background: 'var(--bg-primary)', color: 'var(--accent)', fontSize: '16px',
            cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center',
            alignSelf: i === 0 ? 'flex-end' : 'center', marginBottom: i === 0 ? '0' : undefined,
          }}
          title="Remove row"
        >✕</button>
      </div>
    ))}

    <button
      type="button" onClick={onAdd}
      style={{
        width: '100%', padding: '8px', borderRadius: '8px',
        border: '1.5px dashed var(--border)', background: 'transparent',
        color: 'var(--accent)', fontSize: '13px', fontWeight: 600,
        cursor: 'pointer', fontFamily: 'var(--font-body)',
      }}
    >
      ＋ Add show timing
    </button>

    {rows.length > 0 && (
      <div style={{ marginTop: '8px', padding: '8px 12px', borderRadius: '8px', background: 'var(--accent-dim)', border: '1px solid rgba(224,92,42,0.2)', fontSize: '12px', color: 'var(--accent)' }}>
        💡 Saves will create <strong>{rows.filter(r => r.showDate && r.startTime).length} timing{rows.filter(r => r.showDate && r.startTime).length !== 1 ? 's' : ''}</strong> × selected venues = slots with auto-generated seats
      </div>
    )}
  </div>
);

// ── Main page ─────────────────────────────────────────────────────────────────
const AdminEventsPage = () => {
  const { user } = useAuth();
  const [events, setEvents]       = useState([]);
  const [locations, setLocations] = useState([]);
  const [loading, setLoading]     = useState(true);
  const [modal, setModal]         = useState(false);
  const [form, setForm]           = useState(EMPTY_FORM);
  const [editId, setEditId]       = useState(null);
  const [saving, setSaving]       = useState(false);

  // slot rows: each row = { _id, slotId?, showDate, startTime, endTime }
  // slotId is present only for existing DB slots (edit mode)
  const [slotRows, setSlotRows] = useState([]);

  const load = async () => {
    try {
      const [evRes, locRes] = await Promise.all([
        getEventsByOrganiser(user.userId),
        getAllLocations(),
      ]);
      setEvents(Array.isArray(evRes.data?.data) ? evRes.data.data : []);
      setLocations(Array.isArray(locRes.data?.data) ? locRes.data.data : []);
    } catch { toast.error('Failed to load events'); }
    finally { setLoading(false); }
  };

  useEffect(() => { load(); }, []);

  const openCreate = () => {
    setForm(EMPTY_FORM);
    setSlotRows([]);
    setEditId(null);
    setModal(true);
  };

  const openEdit = async (e) => {
    setForm({
      name:         e.name         || '',
      type:         e.type         || 'MOVIE',
      genres:       parseList(e.genre),
      languages:    parseList(e.language),
      venues:       parseList(e.summary),
      duration:     e.duration     || '',
      categoryName: e.categoryName || '',
      status:       e.status       || 'ACTIVE',
    });
    setEditId(e.eventId);

    // Load existing slots for this event
    try {
      const res  = await getSlotsByEvent(e.eventId);
      const existing = Array.isArray(res.data?.data) ? res.data.data : [];

      // Deduplicate by date+startTime — one row per unique timing
      // (multiple venues create multiple DB slots for the same timing,
      //  we only want one row per timing in the UI)
      const seen = new Set();
      const rows = [];
      existing.forEach((s) => {
        const key = `${s.showDate}|${s.startTime}`;
        if (!seen.has(key)) {
          seen.add(key);
          // Keep all slotIds sharing this timing so we can update them all
          rows.push({
            _id:       key,
            slotIds:   existing.filter((x) => `${x.showDate}|${x.startTime}` === key).map((x) => x.slotId),
            showDate:  s.showDate,
            startTime: s.startTime?.slice(0, 5) || '',
            endTime:   s.endTime?.slice(0, 5)   || '',
          });
        }
      });
      setSlotRows(rows);
    } catch {
      setSlotRows([]);
    }

    setModal(true);
  };

  const handle = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  // Slot row helpers
  const addRow        = ()          => setSlotRows((r) => [...r, newRow()]);
  const removeRow     = (i)         => setSlotRows((r) => r.filter((_, idx) => idx !== i));
  const updateRow     = (i, k, v)   => setSlotRows((r) => r.map((row, idx) => idx === i ? { ...row, [k]: v } : row));

  const save = async () => {
    if (!form.name.trim()) { toast.error('Event name is required'); return; }

    const validRows = slotRows.filter((r) => r.showDate && r.startTime);

    // On create: must pick at least one venue if slot rows exist
    if (!editId && validRows.length > 0 && form.venues.length === 0) {
      toast.error('Select at least one venue to create slots'); return;
    }

    setSaving(true);
    try {
      // 1. Save event
      const payload = {
        name:         form.name,
        type:         form.type,
        status:       form.status,
        duration:     form.duration,
        categoryName: form.categoryName,
        genre:        form.genres.join(','),
        language:     form.languages.join(','),
        summary:      form.venues.join(','),
        organiserId:  user.userId,
      };

      let eventId = editId;
      if (editId) {
        await updateEvent(editId, payload);
      } else {
        const evRes = await createEvent(payload);
        eventId = evRes.data?.data?.eventId ?? evRes.data?.eventId;
      }

      // 2. Resolve locationIds for selected venue names
      const selectedLocations = locations.filter((l) => form.venues.includes(l.locName));

      if (validRows.length > 0 && selectedLocations.length > 0) {
        if (editId) {
          // ── EDIT: update existing slot rows, create new ones ────────────────
          for (const row of validRows) {
            if (row.slotIds?.length) {
              // Existing timing row → update all matching DB slots
              for (const slotId of row.slotIds) {
                await updateSlot(slotId, {
                  eventId:    parseInt(eventId),
                  showDate:   row.showDate,
                  startTime:  row.startTime,
                  endTime:    row.endTime || null,
                  slotStatus: 'AVAILABLE',
                });
              }
            } else {
              // New timing row → create one slot per venue
              for (const loc of selectedLocations) {
                await createSlot({
                  eventId:    parseInt(eventId),
                  locationId: loc.locationId,
                  showDate:   row.showDate,
                  startTime:  row.startTime,
                  endTime:    row.endTime || null,
                  slotStatus: 'AVAILABLE',
                });
              }
            }
          }
        } else {
          // ── CREATE: one slot per row × per venue ────────────────────────────
          const calls = [];
          for (const row of validRows) {
            for (const loc of selectedLocations) {
              calls.push(createSlot({
                eventId:    parseInt(eventId),
                locationId: loc.locationId,
                showDate:   row.showDate,
                startTime:  row.startTime,
                endTime:    row.endTime || null,
                slotStatus: 'AVAILABLE',
              }));
            }
          }
          await Promise.all(calls);
          toast.success(
            `Event created! ${calls.length} slot${calls.length !== 1 ? 's' : ''} auto-generated.`
          );
        }

        if (editId) toast.success('Event & slots updated!');
      } else {
        if (!editId) toast.success('Event created!');
        else         toast.success('Event updated!');
      }

      setModal(false);
      load();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to save');
    } finally {
      setSaving(false);
    }
  };

  const del = async (id) => {
    if (!window.confirm('Delete this event? All its slots will also be deleted.')) return;
    try { await deleteEvent(id); toast.success('Event deleted'); load(); }
    catch (err) { toast.error(err.response?.data?.message || 'Delete failed'); }
  };

  // How many slots will be created/updated — for the info pill in the modal
  const validRowCount      = slotRows.filter((r) => r.showDate && r.startTime).length;
  const newRowCount        = slotRows.filter((r) => r.showDate && r.startTime && !r.slotIds?.length).length;
  const venueCount         = form.venues.length;
  const slotsToBeCreated   = newRowCount * venueCount;

  return (
    <div className="container page-content" style={{ background: 'var(--bg-secondary)', minHeight: '100vh', paddingLeft: '28px', paddingRight: '28px' }}>

      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '12px' }}>
        <div>
          <h1 className="page-title">MY EVENTS</h1>
          <p className="page-subtitle">{events.length} events managed</p>
        </div>
        <button onClick={openCreate} className="btn btn-primary">➕ Create Event</button>
      </div>

      {loading ? (
        <div className="loading-center"><div className="spinner" /></div>
      ) : events.length === 0 ? (
        <div className="empty-state">
          <div className="empty-state-icon">🎭</div>
          <h3>No Events Yet</h3>
          <p style={{ fontSize: '13px' }}>Create your first event to get started</p>
          <button onClick={openCreate} className="btn btn-primary" style={{ marginTop: '16px' }}>Create Event</button>
        </div>
      ) : (
        <div className="grid-3">
          {events.map((e) => {
            const genres    = parseList(e.genre);
            const languages = parseList(e.language);
            const venues    = parseList(e.summary);
            return (
              <div key={e.eventId} className="card" style={{ padding: '20px', borderTop: `3px solid ${TYPE_COLOR[e.type] || 'var(--accent)'}` }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                  <span className={`badge ${e.status === 'ACTIVE' ? 'badge-success' : e.status === 'CANCELLED' ? 'badge-danger' : 'badge-muted'}`}>{e.status}</span>
                  <span style={{ fontSize: '12px', color: TYPE_COLOR[e.type], fontWeight: 600 }}>{e.type}</span>
                </div>

                <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem', marginBottom: '8px' }}>{e.name}</h3>

                {genres.length > 0 && (
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: '4px', marginBottom: '6px' }}>
                    {genres.map((g) => (
                      <span key={g} style={{ fontSize: '10px', fontWeight: 700, padding: '2px 7px', borderRadius: '20px', background: 'var(--bg-secondary)', border: '1px solid var(--border)', color: 'var(--text-secondary)' }}>{g}</span>
                    ))}
                  </div>
                )}

                <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '4px' }}>
                  🌐 {languages.join(', ') || '—'} &nbsp;·&nbsp; ⏱ {e.duration || '—'}
                </div>

                {venues.length > 0 && (
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: '4px', marginBottom: '10px' }}>
                    {venues.map((v) => (
                      <span key={v} style={{ fontSize: '11px', color: 'var(--text-secondary)', fontWeight: 600 }}>📍 {v}</span>
                    ))}
                  </div>
                )}

                <div style={{ display: 'flex', gap: '8px', paddingTop: '12px', borderTop: '1px solid var(--border)' }}>
                  <button onClick={() => openEdit(e)} className="btn btn-secondary btn-sm" style={{ flex: 1 }}>Edit</button>
                  <button onClick={() => del(e.eventId)} className="btn btn-danger btn-sm" style={{ flex: 1 }}>Delete</button>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* ── Modal ── */}
      {modal && (
        <div className="modal-overlay" onClick={() => setModal(false)}>
          <div className="modal" style={{ maxWidth: '640px', maxHeight: '90vh', overflowY: 'auto' }} onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h3 className="modal-title">{editId ? 'EDIT EVENT' : 'CREATE EVENT'}</h3>
              <button className="modal-close" onClick={() => setModal(false)}>✕</button>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>

              {/* Event name */}
              <div className="form-group" style={{ gridColumn: '1/-1' }}>
                <label className="form-label">Event Name *</label>
                <input className="form-input" value={form.name} onChange={(e) => handle('name', e.target.value)} placeholder="e.g. AR Rahman Live" />
              </div>

              {/* Type + Status */}
              <div className="form-group">
                <label className="form-label">Type</label>
                <select className="form-input" value={form.type} onChange={(e) => handle('type', e.target.value)}>
                  {TYPES.map((t) => <option key={t} value={t}>{t}</option>)}
                </select>
              </div>
              <div className="form-group">
                <label className="form-label">Status</label>
                <select className="form-input" value={form.status} onChange={(e) => handle('status', e.target.value)}>
                  {['ACTIVE', 'COMPLETED', 'CANCELLED'].map((s) => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>

              {/* Duration + Category */}
              <div className="form-group">
                <label className="form-label">Duration</label>
                <input className="form-input" value={form.duration} onChange={(e) => handle('duration', e.target.value)} placeholder="2h 30min" />
              </div>
              <div className="form-group">
                <label className="form-label">Category</label>
                <input className="form-input" value={form.categoryName} onChange={(e) => handle('categoryName', e.target.value)} placeholder="e.g. Blockbuster" />
              </div>

              {/* Language */}
              <div style={{ gridColumn: '1/-1' }}>
                <TagPicker label="Language" options={ALL_LANGUAGES} selected={form.languages} onChange={(v) => handle('languages', v)} />
              </div>

              {/* Genre */}
              <div style={{ gridColumn: '1/-1' }}>
                <TagPicker label="Genre" options={ALL_GENRES} selected={form.genres} onChange={(v) => handle('genres', v)} />
              </div>

              {/* Venues */}
              <VenuePicker locations={locations} selected={form.venues} onChange={(v) => handle('venues', v)} />

              {/* ── Slot row builder ── */}
              <SlotBuilder
                rows={slotRows}
                onChange={updateRow}
                onAdd={addRow}
                onRemove={removeRow}
              />

              {/* Summary pill when venues + rows are both filled */}
              {slotsToBeCreated > 0 && (
                <div style={{
                  gridColumn: '1/-1', padding: '10px 14px', borderRadius: '8px',
                  background: 'var(--green-dim)', border: '1px solid rgba(0,214,143,0.2)',
                  fontSize: '13px', color: 'var(--green)',
                }}>
                  ✅ Will create <strong>{slotsToBeCreated} new slot{slotsToBeCreated !== 1 ? 's' : ''}</strong> ({newRowCount} timing{newRowCount !== 1 ? 's' : ''} × {venueCount} venue{venueCount !== 1 ? 's' : ''}) with auto-generated seats
                </div>
              )}

            </div>

            <div style={{ display: 'flex', gap: '12px', marginTop: '16px' }}>
              <button onClick={() => setModal(false)} className="btn btn-secondary" style={{ flex: 1 }}>Cancel</button>
              <button onClick={save} disabled={saving} className="btn btn-primary" style={{ flex: 2 }}>
                {saving ? 'Saving...' : editId ? 'Update Event & Slots' : 'Create Event & Slots'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminEventsPage;
